    // ── Overlay backdrop ────────────────────────────────────────────────────
    const overlay = document.createElement('div');
    overlay.id = 'prembly-pass-overlay';
    overlay.setAttribute('role', 'dialog');
    overlay.setAttribute('aria-modal', 'true');
    overlay.setAttribute('aria-label', 'Prembly identity verification');

    // ── Modal container ─────────────────────────────────────────────────────
    const modal = document.createElement('div');
    modal.id = 'prembly-pass-modal';

    // ── Header ───────────────────────────────────────────────────────────────
    const header = document.createElement('div');
    header.id = 'prembly-pass-header';

    const title = document.createElement('span');
    title.textContent = 'Identity Verification';

    const closeBtn = document.createElement('button');
    closeBtn.id = 'prembly-pass-close';
    closeBtn.setAttribute('aria-label', 'Close verification widget');
    closeBtn.innerHTML = '&times;';
    closeBtn.addEventListener('click', () => this.close());

    header.appendChild(title);
    header.appendChild(closeBtn);

    // ── iframe ───────────────────────────────────────────────────────────────
    const iframe = document.createElement('iframe');
    iframe.id = 'prembly-pass-iframe';
    iframe.src = this.#buildUrl();
    iframe.setAttribute('allow', 'camera; microphone');
    iframe.setAttribute('allowfullscreen', '');

    modal.appendChild(header);
    modal.appendChild(iframe);
    overlay.appendChild(modal);
    document.body.appendChild(overlay);
    this.#overlay = overlay;

    // Close when the user clicks the backdrop (outside the modal)
    overlay.addEventListener('click', (e) => {
      if (e.target === overlay) this.close();
    });

    // ── postMessage listener ────────────────────────────────────────────────
    this._messageHandler = (event) => {
      // Accept messages from the iframe origin and local origin (dev)
      const data = event.data;
      if (!data || typeof data !== 'object') return;

      if (data.type === 'PREMBLY_PASS_SUCCESS') {
        console.log('[PremblyPass] Verification success:', data.payload);
        displayResult('success', data.payload);
        this.#emit('success', data.payload);
        this.close();
      } else if (data.type === 'PREMBLY_PASS_ERROR') {
        console.error('[PremblyPass] Verification error:', data.payload);
        displayResult('error', data.payload);
        this.#emit('error', data.payload);
        this.close();
      } else if (data.type === 'PREMBLY_PASS_CLOSE') {
        this.close();
      }
    };

    window.addEventListener('message', this._messageHandler);
  }

