  #buildUrl() {
    const { app_id, x_api_key, environment, base_url } = this.#config;
    const { config_id, user_ref } = this.#widgetConfig || {};

    const root = base_url || 'https://api.prembly.com';
    const url = new URL('/pass/widget', root);

    url.searchParams.set('app_id', app_id);
    url.searchParams.set('x_api_key', x_api_key);
    url.searchParams.set('environment', environment);
    if (config_id) url.searchParams.set('config_id', config_id);
