        console.error('[PremblyPass] Verification error:', data.payload);
        displayResult('error', data.payload);
        this.#emit('error', data.payload);
        this.close();
      } else if (data.type === 'PREMBLY_PASS_CLOSE') {
        this.close();
      }
    };

    window.addEventListener('message', this._messageHandler);
  }

