// ---------------------------------------------------------------------------
// PremblyPass widget
// A lightweight wrapper that launches the Prembly Pass hosted verification
// flow inside a modal iframe and surfaces `success` / `error` events via
// a simple EventEmitter-style API.
// ---------------------------------------------------------------------------

class PremblyPass {
  #config;
  #widgetConfig;
  #listeners = {};
  #overlay = null;

  /**
   * @param {object} options
   * @param {string} options.app_id        - Your Prembly application ID
   * @param {string} options.x_api_key     - Your Prembly API key
   * @param {string} [options.environment] - 'test' | 'live'  (default: 'test')
   * @param {string} [options.base_url]    - Override the Prembly base URL
   */
  constructor({ app_id, x_api_key, environment = 'test', base_url }) {
    this.#config = { app_id, x_api_key, environment, base_url };

    // Expose the underlying SDK so callers can run data / doc verifications
    this.sdk = new PremblyDataVerification({ app_id, x_api_key, environment });
  }

  /**
   * Set per-session widget configuration before calling open().
   * @param {object} cfg
   * @param {string} cfg.config_id - Prembly Pass configuration/flow ID
   * @param {string} cfg.user_ref  - Unique reference for this verification session
   */
  setup(cfg) {
    this.#widgetConfig = cfg;
    return this;
  }

  /** Register an event listener.  Supported events: 'success', 'error', 'close' */
  on(event, handler) {
    if (!this.#listeners[event]) this.#listeners[event] = [];
    this.#listeners[event].push(handler);
    return this;
  }

  #emit(event, data) {
    (this.#listeners[event] || []).forEach((fn) => fn(data));
  }

  /** Build the widget iframe URL */
  #buildUrl() {
    const { app_id, x_api_key, environment, base_url } = this.#config;
    const { config_id, user_ref } = this.#widgetConfig || {};

    const root = base_url || 'https://api.prembly.com';
    const url = new URL('/pass/widget', root);

    url.searchParams.set('app_id', app_id);
    url.searchParams.set('x_api_key', x_api_key);
    url.searchParams.set('environment', environment);
    if (config_id) url.searchParams.set('config_id', config_id);
    if (user_ref) url.searchParams.set('user_ref', user_ref);

    return url.toString();
  }

  /** Launch the verification widget in a modal overlay */
  open() {
    if (this.#overlay) return; // already open

    // ── Overlay backdrop ────────────────────────────────────────────────────
    const overlay = document.createElement('div');
    overlay.id = 'prembly-pass-overlay';
    overlay.setAttribute('role', 'dialog');
    overlay.setAttribute('aria-modal', 'true');
    overlay.setAttribute('aria-label', 'Prembly identity verification');

    // ── Modal container ─────────────────────────────────────────────────────
    const modal = document.createElement('div');
    modal.id = 'prembly-pass-modal';

    // ── Header ───────────────────────────────────────────────────────────────
    const header = document.createElement('div');
    header.id = 'prembly-pass-header';

    const title = document.createElement('span');
    title.textContent = 'Identity Verification';

    const closeBtn = document.createElement('button');
    closeBtn.id = 'prembly-pass-close';
    closeBtn.setAttribute('aria-label', 'Close verification widget');
    closeBtn.innerHTML = '&times;';
    closeBtn.addEventListener('click', () => this.close());

    header.appendChild(title);
    header.appendChild(closeBtn);

    // ── iframe ───────────────────────────────────────────────────────────────
    const iframe = document.createElement('iframe');
    iframe.id = 'prembly-pass-iframe';
    iframe.src = this.#buildUrl();
    iframe.setAttribute('allow', 'camera; microphone');
    iframe.setAttribute('allowfullscreen', '');

    modal.appendChild(header);
    modal.appendChild(iframe);
    overlay.appendChild(modal);
    document.body.appendChild(overlay);
    this.#overlay = overlay;

    // Close when the user clicks the backdrop (outside the modal)
    overlay.addEventListener('click', (e) => {
      if (e.target === overlay) this.close();
    });

    // ── postMessage listener ────────────────────────────────────────────────
    this._messageHandler = (event) => {
      const data = event.data;
      if (!data || typeof data !== 'object') return;

      if (data.type === 'PREMBLY_PASS_SUCCESS') {
        console.log('[PremblyPass] Verification success:', data.payload);
        displayResult('success', data.payload);
        this.#emit('success', data.payload);
        this.close();
      } else if (data.type === 'PREMBLY_PASS_ERROR') {
        console.error('[PremblyPass] Verification error:', data.payload);
        displayResult('error', data.payload);
        this.#emit('error', data.payload);
        this.close();
      } else if (data.type === 'PREMBLY_PASS_CLOSE') {
        this.close();
      }
    };

    window.addEventListener('message', this._messageHandler);
  }

  /** Close and tear down the modal */
  close() {
    if (!this.#overlay) return;
    document.body.removeChild(this.#overlay);
    this.#overlay = null;
    window.removeEventListener('message', this._messageHandler);
    this.#emit('close', null);
  }
}

